UPDATE #{SCHEMA_NAME}.nifi_${table_name} u SET
mgr_status = '2',
mgr_error = 'comp_id is incorrect for tenant'
WHERE u.comp_id != #{COMP_ID}
and u.mgr_status !='1'
;

WITH nifi_audit_values AS (
    SELECT 
        date_create, 
        time_create,
        lastupdated
    FROM kopdev.nifi_audit
    WHERE id = (
        SELECT MAX(id) FROM kopdev.nifi_audit
        WHERE comp_id = #{COMP_ID}
    )
    AND comp_id = #{COMP_ID}
    LIMIT 1
)

UPDATE #{SCHEMA_NAME}.NIFI_${table_name} u
SET 
    date_create = (
        SELECT date_create FROM nifi_audit_values
        ),
    time_create = (
        SELECT time_create FROM nifi_audit_values
        ),
	lastupdated = (
        SELECT lastupdated FROM nifi_audit_values
        )
WHERE u.mgr_status = '0'
AND u.comp_id = #{COMP_ID}
;

SELECT mgr_id
FROM #{SCHEMA_NAME}.NIFI_${table_name} u
WHERE u.mgr_status = '0' 
AND u.user_create = '#{USER_CREATE}' 
AND u.comp_id = #{COMP_ID}
LIMIT #{BATCH_SIZE};

UPDATE general_definition.gen_company SET
invoice_bank_id_1 = (SELECT MAX(bank_id) FROM #{SCHEMA_NAME}.${table_name} WHERE user_create = '#{USER_CREATE}' AND comp_id = #{COMP_ID}),
invoice_bank_id_2 = (SELECT MIN(bank_id) FROM #{SCHEMA_NAME}.${table_name} WHERE user_create = '#{USER_CREATE}' AND comp_id = #{COMP_ID})
WHERE comp_id = #{COMP_ID}
AND invoice_bank_id_1 IS NULL
AND invoice_bank_id_2 IS NULL;

UPDATE #{SCHEMA_NAME}.NIFI_${table_name} u SET 
	"oid" = #{SCHEMA_NAME}.get_oid(),
	user_create = '#{USER_CREATE}'
WHERE u.mgr_status='0' 
AND u.comp_id = #{COMP_ID}
;

--Insert into mapping table
INSERT INTO #{SCHEMA_NAME}.NIFI_${table_name}_MAPPING (BANK_ID, STATUS, ACTIVE_FLAG, COMP_ID)
SELECT BANK_ID, STATUS, ACTIVE_FLAG, #{COMP_ID}
FROM #{SCHEMA_NAME}.NIFI_${table_name} u
WHERE comp_id = #{COMP_ID}
AND user_create = '#{USER_CREATE}'
AND mgr_status = 1
AND mgr_id = ${mgr_id}
AND NOT EXISTS (
  SELECT 1
  FROM #{SCHEMA_NAME}.NIFI_${table_name}_MAPPING m
  WHERE m.bank_id = u.bank_id
  AND m.comp_id = #{COMP_ID}
)
AND EXISTS (
  SELECT 1
  FROM #{SCHEMA_NAME}.${table_name} f
  WHERE f.comp_id = #{COMP_ID}
  AND f.user_create = '#{USER_CREATE}'
  AND f.bank_id = u.bank_id
);

WITH temp AS (
    SELECT #{SCHEMA_NAME}.get_lastupdated() AS lastupdated_value
)

INSERT INTO #{SCHEMA_NAME}.${table_name} (lastupdated, ${insert_query})
SELECT
    t.lastupdated_value,
	${insert_query}
FROM #{SCHEMA_NAME}.NIFI_${table_name} u 
CROSS JOIN temp t
WHERE u.comp_id = #{COMP_ID} 
AND u.mgr_status = '0' 
AND u.mgr_id = ${mgr_id}
